import os
import base64
from cryptography.fernet import Fernet
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC
from cryptography.hazmat.primitives import hashes


class CreditCardEncryptor:
    """
    Encrypts and decrypts credit card numbers using Fernet (AES-128-CBC)
    symmetric encryption from the cryptography library.
    """

    def __init__(self, encryption_key: str, salt: str = None):
        """
        Initialize the encryptor with a key derived from the provided
        encryption key using PBKDF2.

        Args:
            encryption_key: The base encryption key (should be loaded from
                           a secure secret manager, NOT hardcoded).
            salt: A salt for key derivation. Should be unique per deployment
                  and stored securely alongside the key.
        """
        if not encryption_key:
            raise ValueError("Encryption key must not be empty")

        if salt is None:
            raise ValueError(
                "A salt must be provided. Generate one with os.urandom(16) "
                "and store it securely alongside your encryption key."
            )

        if isinstance(salt, str):
            salt_bytes = salt.encode("utf-8")
        else:
            salt_bytes = salt

        # Derive a proper Fernet key from the provided key using PBKDF2
        kdf = PBKDF2HMAC(
            algorithm=hashes.SHA256(),
            length=32,
            salt=salt_bytes,
            iterations=480_000,  # OWASP recommended minimum
        )
        derived_key = base64.urlsafe_b64encode(
            kdf.derive(encryption_key.encode("utf-8"))
        )
        self._fernet = Fernet(derived_key)

    def encrypt_card_number(self, card_number: str) -> str:
        """
        Encrypt a credit card number.

        Args:
            card_number: The plaintext credit card number (digits only or
                        with dashes/spaces).

        Returns:
            A base64-encoded encrypted string safe for database storage.
        """
        # Validate and normalize the card number
        normalized = self._normalize_card_number(card_number)
        self._validate_card_number(normalized)

        encrypted_bytes = self._fernet.encrypt(normalized.encode("utf-8"))
        return encrypted_bytes.decode("utf-8")

    def decrypt_card_number(self, encrypted_card: str) -> str:
        """
        Decrypt an encrypted credit card number.

        Args:
            encrypted_card: The encrypted card string from the database.

        Returns:
            The original plaintext credit card number.
        """
        if not encrypted_card:
            raise ValueError("Encrypted card data must not be empty")

        decrypted_bytes = self._fernet.decrypt(encrypted_card.encode("utf-8"))
        return decrypted_bytes.decode("utf-8")

    def get_masked_card_number(self, card_number: str) -> str:
        """
        Return a masked version of the card number for display purposes.
        Shows only the last 4 digits.

        Args:
            card_number: The plaintext credit card number.

        Returns:
            Masked card number like '****-****-****-1234'.
        """
        normalized = self._normalize_card_number(card_number)
        last_four = normalized[-4:]
        return f"****-****-****-{last_four}"

    @staticmethod
    def _normalize_card_number(card_number: str) -> str:
        """Remove spaces and dashes from card number."""
        if not card_number:
            raise ValueError("Card number must not be empty")
        return card_number.replace(" ", "").replace("-", "")

    @staticmethod
    def _validate_card_number(card_number: str) -> None:
        """Basic validation of card number format."""
        if not card_number.isdigit():
            raise ValueError("Card number must contain only digits")
        if len(card_number) < 13 or len(card_number) > 19:
            raise ValueError("Card number must be between 13 and 19 digits")

    @staticmethod
    def generate_key() -> str:
        """
        Generate a new random encryption key.
        Store this securely in a secrets manager (e.g., AWS Secrets Manager,
        HashiCorp Vault, Azure Key Vault) — NOT in source code or plain
        config files.

        Returns:
            A URL-safe base64-encoded random key string.
        """
        return base64.urlsafe_b64encode(os.urandom(32)).decode("utf-8")

    @staticmethod
    def generate_salt() -> str:
        """
        Generate a new random salt for key derivation.
        Store this securely alongside the encryption key.

        Returns:
            A hex-encoded random salt string.
        """
        return os.urandom(16).hex()


