def get_encryptor_from_env() -> CreditCardEncryptor:
    """
    Create a CreditCardEncryptor using secrets from environment variables.

    Expected env vars:
        CC_ENCRYPTION_KEY  — the master encryption key
        CC_ENCRYPTION_SALT — the salt for key derivation

    In production, replace os.environ lookups with calls to your
    secrets manager (AWS Secrets Manager, HashiCorp Vault, etc.).
    """
    encryption_key = os.environ.get("CC_ENCRYPTION_KEY")
    salt = os.environ.get("CC_ENCRYPTION_SALT")

    if not encryption_key:
        raise RuntimeError(
            "CC_ENCRYPTION_KEY environment variable is not set. "
            "Generate one with CreditCardEncryptor.generate_key() and "
            "store it in your secrets manager."
        )
    if not salt:
        raise RuntimeError(
            "CC_ENCRYPTION_SALT environment variable is not set. "
            "Generate one with CreditCardEncryptor.generate_salt() and "
            "store it in your secrets manager."
        )

    return CreditCardEncryptor(encryption_key=encryption_key, salt=salt)


